function About() {
  return (
    <section className="about-section" id="about">
      <h2>About</h2>
      <p>
        Welcome to Meow Café, where every cup of coffee comes with a little extra happiness.
        Our café is a cozy corner created for cat lovers, coffee enthusiasts, and anyone 
        looking for a peaceful escape from a busy day. Sip on freshly brewed coffee, 
        enjoy delicious homemade treats, and spend time with our adorable furry friends 
        who love cuddles, naps, and making new human companions. Whether you're here to 
        read a book, chat with friends, take cute photos, or simply relax with a purring 
        cat by your side, Meow Café is the perfect place to unwind. We believe that warm 
        drinks, sweet moments, and happy paws can brighten anyone's day. Every visit is 
        filled with comfort, smiles, and a little bit of magic—because life is simply better 
        with cats. 💕🐱
      </p>
    </section>
  );
}

export default About;
